drawForSelection(count: number = ${choiceCount}): T[] {
  if (this.items.length === 0) {
    print(`[Rune Weaver] ${className}: No items in pool`);
    return [];
  }

  const result: T[] = [];
  const drawnIds = new Set<string>();
  const ownedIds = ${hasSessionState ? "new Set(this.sessionState.ownedTalentIds)" : "new Set<string>()"};${hasSessionState ? `
  let availableItems = this.items.filter(item => 
    this.sessionState.remainingTalentIds.includes((item.item as any).id)
  );` : `
  let availableItems = [...this.items];`}

  // Filter out owned items (already acquired)
  availableItems = availableItems.filter(item => !ownedIds.has((item.item as any).id));

  if (availableItems.length === 0) {
    print(`[Rune Weaver] ${className}: No available items in session pool`);
    return [];
  }

  // Group available items by tier
  const tierGroups = new Map<number, WeightedItem<T>[]>();
  for (const item of availableItems) {
    const tier = item.tier || 0;
    if (!tierGroups.has(tier)) {
      tierGroups.set(tier, []);
    }
    tierGroups.get(tier)!.push(item);
  }

  const distinctTiers = Array.from(tierGroups.keys()).sort((a, b) => a - b);

  // Phase 1: Draw one from each distinct tier to ensure rarity diversity
  for (const tier of distinctTiers) {
    if (result.length >= count) break;
    const tierItems = tierGroups.get(tier)!.filter(item => {
      const id = (item.item as any).id as string;
      return !drawnIds.has(id);
    });
    if (tierItems.length === 0) continue;

    const tierTotalWeight = tierItems.reduce((sum, item) => sum + item.weight, 0);
    if (tierTotalWeight <= 0) continue;

    let random = RandomFloat(0, tierTotalWeight);
    let drawnItem: WeightedItem<T> | null = null;
    for (const item of tierItems) {
      random -= item.weight;
      if (random <= 0) {
        drawnItem = item;
        break;
      }
    }

    if (drawnItem) {
      const itemId = (drawnItem.item as any).id as string;
      if ("${duplicatePolicy}" === "forbid" && drawnIds.has(itemId)) {
        continue;
      }
      result.push(drawnItem.item);
      drawnIds.add(itemId);
    }
  }
